-- 181b_tarot_minor_i18n_seed.sql
-- Faz 4 devam: Minor Arcana 56 kart için EN+DE i18n.

INSERT INTO tarot_card_i18n (id, card_id, locale, name, upright_meaning, reversed_meaning, keywords)
SELECT UUID(), c.id, v.locale, v.name, v.upright_meaning, v.reversed_meaning, v.keywords
FROM tarot_cards c
JOIN (
  SELECT 'ace-of-cups' slug, 'en' locale, 'Ace of Cups' name, 'New emotional beginning, love, happiness and intuition.' upright_meaning, 'Emotional block, suppressed feelings and separation.' reversed_meaning, '["love","emotion","beginning"]' keywords
  UNION ALL SELECT 'ace-of-cups','de','Ass der Kelche','Neuer emotionaler Anfang, Liebe, Freude und Intuition.','Emotionale Blockade, unterdrückte Gefühle und Trennung.','["liebe","gefühl","anfang"]'
  UNION ALL SELECT 'two-of-cups','en','Two of Cups','Mutual love, partnership, harmony, attraction and agreement.','Disharmony, resentment, imbalance in relationship and separation.','["partnership","harmony","attraction"]'
  UNION ALL SELECT 'two-of-cups','de','Zwei der Kelche','Gegenseitige Liebe, Partnerschaft, Harmonie, Anziehung und Einigung.','Disharmonie, Groll, Ungleichgewicht in Beziehungen und Trennung.','["partnerschaft","harmonie","anziehung"]'
  UNION ALL SELECT 'three-of-cups','en','Three of Cups','Friendship, celebration, community, joy and shared success.','Loneliness, gossip, social disconnection and excess.','["friendship","celebration","community"]'
  UNION ALL SELECT 'three-of-cups','de','Drei der Kelche','Freundschaft, Feier, Gemeinschaft, Freude und geteilter Erfolg.','Einsamkeit, Klatsch, soziale Distanz und Übertreibung.','["freundschaft","feier","gemeinschaft"]'
  UNION ALL SELECT 'four-of-cups','en','Four of Cups','Introspection, dissatisfaction, missed opportunities and stagnation.','New awareness, motivation and accepting opportunities.','["dissatisfaction","introspection","opportunity"]'
  UNION ALL SELECT 'four-of-cups','de','Vier der Kelche','Innenschau, Unzufriedenheit, übersehene Chancen und Stillstand.','Neue Erkenntnis, Motivation und Annahme von Chancen.','["unzufriedenheit","innenschau","chance"]'
  UNION ALL SELECT 'five-of-cups','en','Five of Cups','Loss, disappointment, sadness and not seeing what remains.','Acceptance, healing, noticing what remains and hope.','["loss","grief","acceptance"]'
  UNION ALL SELECT 'five-of-cups','de','Fünf der Kelche','Verlust, Enttäuschung, Traurigkeit und das Übersehen des Verbleibenden.','Akzeptanz, Heilung, Blick auf das Verbleibende und Hoffnung.','["verlust","trauer","annahme"]'
  UNION ALL SELECT 'six-of-cups','en','Six of Cups','Nostalgia, childhood, innocence and kindness from the past.','Clinging to the past, maturing and letting go.','["nostalgia","innocence","past"]'
  UNION ALL SELECT 'six-of-cups','de','Sechs der Kelche','Nostalgie, Kindheit, Unschuld und Güte aus der Vergangenheit.','Festhalten an der Vergangenheit, Reifung und Loslassen.','["nostalgie","unschuld","vergangenheit"]'
  UNION ALL SELECT 'seven-of-cups','en','Seven of Cups','Dreams, choices, illusion, fantasy and indecision.','Clarity, return to reality, focus and choice.','["dream","choice","illusion"]'
  UNION ALL SELECT 'seven-of-cups','de','Sieben der Kelche','Träume, Möglichkeiten, Illusion, Fantasie und Unentschlossenheit.','Klarheit, Rückkehr zur Realität, Fokus und Wahl.','["traum","wahl","illusion"]'
  UNION ALL SELECT 'eight-of-cups','en','Eight of Cups','Letting go, search for meaning, turning toward something deeper and departure.','Returning to the past, inability to let go and hesitant separation.','["letting_go","search","departure"]'
  UNION ALL SELECT 'eight-of-cups','de','Acht der Kelche','Loslassen, Sinnsuche, Hinwendung zu etwas Tieferem und Aufbruch.','Rückkehr zur Vergangenheit, Nicht-loslassen-können und zögerlicher Abschied.','["loslassen","suche","aufbruch"]'
  UNION ALL SELECT 'nine-of-cups','en','Nine of Cups','Wish card, satisfaction, happiness and success fulfilled.','Surface happiness, dissatisfaction and pride.','["wish","satisfaction","happiness"]'
  UNION ALL SELECT 'nine-of-cups','de','Neun der Kelche','Wunschkarte, Zufriedenheit, Glück und erfüllter Erfolg.','Oberflächliches Glück, Unzufriedenheit und Stolz.','["wunsch","zufriedenheit","glück"]'
  UNION ALL SELECT 'ten-of-cups','en','Ten of Cups','Family happiness, harmony, emotional completion and peace.','Family conflict, disharmony and disconnected bonds.','["family","happiness","harmony"]'
  UNION ALL SELECT 'ten-of-cups','de','Zehn der Kelche','Familiäres Glück, Harmonie, emotionale Erfüllung und Frieden.','Familienkonflikt, Disharmonie und gelöste Bindungen.','["familie","glück","harmonie"]'
  UNION ALL SELECT 'page-of-cups','en','Page of Cups','Creative news, romantic offer, intuitive message and dreaminess.','Emotional immaturity, blockage and disappointing news.','["message","romance","creativity"]'
  UNION ALL SELECT 'page-of-cups','de','Page der Kelche','Kreative Nachricht, romantisches Angebot, intuitive Botschaft und Träumerei.','Emotionale Unreife, Blockade und enttäuschende Nachricht.','["botschaft","romantik","kreativität"]'
  UNION ALL SELECT 'knight-of-cups','en','Knight of Cups','Romantic offer, idealism, emotional mission and charm.','Misleading romance, passive aggression and indecision.','["romance","offer","idealism"]'
  UNION ALL SELECT 'knight-of-cups','de','Ritter der Kelche','Romantisches Angebot, Idealismus, emotionale Mission und Charme.','Täuschende Romantik, passive Aggression und Unentschlossenheit.','["romantik","angebot","idealismus"]'
  UNION ALL SELECT 'queen-of-cups','en','Queen of Cups','Compassion, intuition, emotional maturity and empathy.','Over-sensitivity, manipulation and dependency.','["compassion","intuition","empathy"]'
  UNION ALL SELECT 'queen-of-cups','de','Königin der Kelche','Mitgefühl, Intuition, emotionale Reife und Empathie.','Überempfindlichkeit, Manipulation und Abhängigkeit.','["mitgefühl","intuition","empathie"]'
  UNION ALL SELECT 'king-of-cups','en','King of Cups','Emotional balance, wisdom, diplomacy and calm leadership.','Passive aggression, emotional manipulation and lack of control.','["balance","wisdom","diplomacy"]'
  UNION ALL SELECT 'king-of-cups','de','König der Kelche','Emotionale Balance, Weisheit, Diplomatie und ruhige Führung.','Passive Aggression, emotionale Manipulation und Kontrollverlust.','["balance","weisheit","diplomatie"]'

  UNION ALL SELECT 'ace-of-swords','en','Ace of Swords','Mental clarity, new idea, victory and honesty.','Confusion, broken communication and injustice.','["mind","idea","clarity"]'
  UNION ALL SELECT 'ace-of-swords','de','Ass der Schwerter','Geistige Klarheit, neue Idee, Sieg und Ehrlichkeit.','Verwirrung, gestörte Kommunikation und Ungerechtigkeit.','["geist","idee","klarheit"]'
  UNION ALL SELECT 'two-of-swords','en','Two of Swords','Indecision, deadlock, search for balance and not seeing the truth.','Decision, facing truth and unlocking the block.','["indecision","deadlock","balance"]'
  UNION ALL SELECT 'two-of-swords','de','Zwei der Schwerter','Unentschlossenheit, Sackgasse, Suche nach Balance und Vermeidung der Wahrheit.','Entscheidung, Wahrheit ansehen und Blockade lösen.','["unentschlossenheit","sackgasse","balance"]'
  UNION ALL SELECT 'three-of-swords','en','Three of Swords','Heartbreak, sadness, betrayal, separation and painful truth.','Healing, forgiveness and releasing pain.','["heartbreak","sadness","separation"]'
  UNION ALL SELECT 'three-of-swords','de','Drei der Schwerter','Herzschmerz, Trauer, Verrat, Trennung und schmerzhafte Wahrheit.','Heilung, Vergebung und Loslassen des Schmerzes.','["herzschmerz","trauer","trennung"]'
  UNION ALL SELECT 'four-of-swords','en','Four of Swords','Rest, retreat, healing and inner recovery.','Burnout, inability to rest and forced continuation.','["rest","healing","pause"]'
  UNION ALL SELECT 'four-of-swords','de','Vier der Schwerter','Ruhe, Rückzug, Heilung und innere Erholung.','Erschöpfung, fehlende Ruhe und erzwungenes Weitermachen.','["ruhe","heilung","pause"]'
  UNION ALL SELECT 'five-of-swords','en','Five of Swords','Conflict, winning at a cost, pride and aggression.','Peace, withdrawal, ending conflict and reconciliation.','["conflict","pride","loss"]'
  UNION ALL SELECT 'five-of-swords','de','Fünf der Schwerter','Konflikt, Sieg um jeden Preis, Stolz und Aggression.','Frieden, Rückzug, Konflikt beenden und Versöhnung.','["konflikt","stolz","verlust"]'
  UNION ALL SELECT 'six-of-swords','en','Six of Swords','Transition, leaving difficulty behind and journey toward healing.','Clinging to the past, inability to move and resistance.','["transition","journey","healing"]'
  UNION ALL SELECT 'six-of-swords','de','Sechs der Schwerter','Übergang, schwierige Lage verlassen und Reise zur Heilung.','Festhalten an der Vergangenheit, Stillstand und Widerstand.','["übergang","reise","heilung"]'
  UNION ALL SELECT 'seven-of-swords','en','Seven of Swords','Strategy, indirect path, deceit, secrecy and escape.','Honesty, confession, guilt and being exposed.','["strategy","secrecy","deceit"]'
  UNION ALL SELECT 'seven-of-swords','de','Sieben der Schwerter','Strategie, Umweg, Täuschung, Geheimhaltung und Flucht.','Ehrlichkeit, Geständnis, Schuld und Entlarvung.','["strategie","geheimnis","täuschung"]'
  UNION ALL SELECT 'eight-of-swords','en','Eight of Swords','Feeling restricted, mental prison and helplessness.','Liberation, awareness and breaking restriction.','["restriction","helplessness","prison"]'
  UNION ALL SELECT 'eight-of-swords','de','Acht der Schwerter','Gefühl der Einschränkung, mentales Gefängnis und Hilflosigkeit.','Befreiung, Bewusstsein und Durchbrechen der Begrenzung.','["begrenzung","hilflosigkeit","gefängnis"]'
  UNION ALL SELECT 'nine-of-swords','en','Nine of Swords','Anxiety, nightmare, worry, guilt and sleeplessness.','Moving out of worry, sharing and beginning to heal.','["anxiety","worry","nightmare"]'
  UNION ALL SELECT 'nine-of-swords','de','Neun der Schwerter','Angst, Albtraum, Sorge, Schuld und Schlaflosigkeit.','Aus der Sorge herausfinden, teilen und Heilung beginnen.','["angst","sorge","albtraum"]'
  UNION ALL SELECT 'ten-of-swords','en','Ten of Swords','Rock bottom, ending, betrayal and painful close before renewal.','Beginning of healing, rising from the bottom and renewal.','["bottom","ending","renewal"]'
  UNION ALL SELECT 'ten-of-swords','de','Zehn der Schwerter','Tiefpunkt, Ende, Verrat und schmerzhafter Abschluss vor Erneuerung.','Beginn der Heilung, Aufstehen vom Tiefpunkt und Erneuerung.','["tiefpunkt","ende","erneuerung"]'
  UNION ALL SELECT 'page-of-swords','en','Page of Swords','Curiosity, new idea, mental exploration and direct communication.','Gossip, defensive communication and scattered thinking.','["curiosity","idea","communication"]'
  UNION ALL SELECT 'page-of-swords','de','Page der Schwerter','Neugier, neue Idee, geistige Erkundung und direkte Kommunikation.','Klatsch, defensive Kommunikation und zerstreutes Denken.','["neugier","idee","kommunikation"]'
  UNION ALL SELECT 'knight-of-swords','en','Knight of Swords','Fast action, determination, struggle and mental courage.','Haste, impulsiveness and uncalculated risk.','["speed","courage","struggle"]'
  UNION ALL SELECT 'knight-of-swords','de','Ritter der Schwerter','Schnelles Handeln, Entschlossenheit, Kampf und geistiger Mut.','Hast, Impulsivität und unbedachtes Risiko.','["tempo","mut","kampf"]'
  UNION ALL SELECT 'queen-of-swords','en','Queen of Swords','Independent mind, honesty, boundaries and wisdom through experience.','Harshness, coldness, criticism and resentment.','["independence","honesty","boundary"]'
  UNION ALL SELECT 'queen-of-swords','de','Königin der Schwerter','Unabhängiger Geist, Ehrlichkeit, Grenzen und Weisheit durch Erfahrung.','Härte, Kälte, Kritik und Groll.','["unabhängigkeit","ehrlichkeit","grenze"]'
  UNION ALL SELECT 'king-of-swords','en','King of Swords','Justice, logic, authority, ethical leadership and clear mind.','Harshness, manipulation, cold judgment and tyranny.','["justice","logic","authority"]'
  UNION ALL SELECT 'king-of-swords','de','König der Schwerter','Gerechtigkeit, Logik, Autorität, ethische Führung und klarer Geist.','Härte, Manipulation, kaltes Urteil und Tyrannei.','["gerechtigkeit","logik","autorität"]'

  UNION ALL SELECT 'ace-of-wands','en','Ace of Wands','Inspiration, new passion, creativity and energy.','Delay, loss of motivation and creative block.','["passion","inspiration","energy"]'
  UNION ALL SELECT 'ace-of-wands','de','Ass der Stäbe','Inspiration, neue Leidenschaft, Kreativität und Energie.','Verzögerung, Motivationsverlust und kreative Blockade.','["leidenschaft","inspiration","energie"]'
  UNION ALL SELECT 'two-of-wands','en','Two of Wands','Planning, future vision, moment of choice and horizon.','Fear, lack of planning and missed opportunities.','["plan","vision","choice"]'
  UNION ALL SELECT 'two-of-wands','de','Zwei der Stäbe','Planung, Zukunftsvision, Entscheidungsmoment und Horizont.','Angst, Planlosigkeit und verpasste Chancen.','["plan","vision","wahl"]'
  UNION ALL SELECT 'three-of-wands','en','Three of Wands','Expansion, opportunities, vision becoming real and expectation.','Obstacles, delay and narrow perspective.','["expansion","opportunity","expectation"]'
  UNION ALL SELECT 'three-of-wands','de','Drei der Stäbe','Erweiterung, Chancen, Verwirklichung der Vision und Erwartung.','Hindernisse, Verzögerung und enger Blick.','["erweiterung","chance","erwartung"]'
  UNION ALL SELECT 'four-of-wands','en','Four of Wands','Celebration, home, stability, rooting and threshold of success.','Temporary disharmony, moving and tension at a threshold.','["celebration","home","stability"]'
  UNION ALL SELECT 'four-of-wands','de','Vier der Stäbe','Feier, Zuhause, Stabilität, Verwurzelung und Erfolgsschwelle.','Vorübergehende Disharmonie, Umzug und Spannung an einer Schwelle.','["feier","zuhause","stabilität"]'
  UNION ALL SELECT 'five-of-wands','en','Five of Wands','Conflict, competition, differences of opinion and small tensions.','Agreement, avoiding conflict and inner conflict.','["competition","conflict","tension"]'
  UNION ALL SELECT 'five-of-wands','de','Fünf der Stäbe','Konflikt, Wettbewerb, Meinungsverschiedenheiten und kleine Spannungen.','Einigung, Konfliktvermeidung und innerer Konflikt.','["wettbewerb","konflikt","spannung"]'
  UNION ALL SELECT 'six-of-wands','en','Six of Wands','Victory, recognition, success, appreciation and leadership.','Lack of recognition, search for success, ego and pride.','["victory","success","recognition"]'
  UNION ALL SELECT 'six-of-wands','de','Sechs der Stäbe','Sieg, Anerkennung, Erfolg, Wertschätzung und Führung.','Mangel an Anerkennung, Erfolgssuche, Ego und Stolz.','["sieg","erfolg","anerkennung"]'
  UNION ALL SELECT 'seven-of-wands','en','Seven of Wands','Defending position, struggle, resilience and will.','Withdrawal, yielding to pressure and fatigue.','["defense","will","struggle"]'
  UNION ALL SELECT 'seven-of-wands','de','Sieben der Stäbe','Position verteidigen, Kampf, Ausdauer und Wille.','Rückzug, Nachgeben unter Druck und Müdigkeit.','["verteidigung","wille","kampf"]'
  UNION ALL SELECT 'eight-of-wands','en','Eight of Wands','Fast news, movement, momentum, direct action and message.','Delay, stagnation and communication block.','["speed","movement","message"]'
  UNION ALL SELECT 'eight-of-wands','de','Acht der Stäbe','Schnelle Nachricht, Bewegung, Schwung, direktes Handeln und Botschaft.','Verzögerung, Stillstand und Kommunikationshindernis.','["tempo","bewegung","botschaft"]'
  UNION ALL SELECT 'nine-of-wands','en','Nine of Wands','Resilience, last stretch, protection and experience.','Exhaustion, paranoia and defensive closure.','["resilience","endurance","protection"]'
