  UNION ALL SELECT 'ten-of-wands','en','Ten of Wands','Burden, too much responsibility, final stage and heavy carrying.','Release of burden, delegation and lightness.','["burden","responsibility","weight"]'
  UNION ALL SELECT 'ten-of-wands','de','Zehn der Stäbe','Last, zu viel Verantwortung, Schlussphase und schweres Tragen.','Last ablegen, abgeben und leichter werden.','["last","verantwortung","gewicht"]'
  UNION ALL SELECT 'page-of-wands','en','Page of Wands','New idea, inspiration, discovery and eager beginning.','Disappointment, lack of planning and scattered inspiration.','["inspiration","discovery","enthusiasm"]'
  UNION ALL SELECT 'page-of-wands','de','Page der Stäbe','Neue Idee, Inspiration, Entdeckung und begeisterter Anfang.','Enttäuschung, Planlosigkeit und zerstreute Inspiration.','["inspiration","entdeckung","begeisterung"]'
  UNION ALL SELECT 'knight-of-wands','en','Knight of Wands','Passion, adventure, breakthrough, charisma and fast action.','Rushed decision, unplanned risk and fading fire.','["adventure","passion","breakthrough"]'
  UNION ALL SELECT 'knight-of-wands','de','Ritter der Stäbe','Leidenschaft, Abenteuer, Aufbruch, Charisma und schnelles Handeln.','Übereilte Entscheidung, ungeplantes Risiko und erlöschendes Feuer.','["abenteuer","leidenschaft","aufbruch"]'
  UNION ALL SELECT 'queen-of-wands','en','Queen of Wands','Confidence, charisma, warm leadership and creative power.','Jealousy, demanding energy and scattered force.','["confidence","charisma","leadership"]'
  UNION ALL SELECT 'queen-of-wands','de','Königin der Stäbe','Selbstvertrauen, Charisma, warme Führung und kreative Kraft.','Eifersucht, fordernde Energie und zerstreute Kraft.','["selbstvertrauen","charisma","führung"]'
  UNION ALL SELECT 'king-of-wands','en','King of Wands','Visionary leadership, inspiration, entrepreneurship and natural authority.','Domination, impatience and inflated ego.','["vision","leadership","enterprise"]'
  UNION ALL SELECT 'king-of-wands','de','König der Stäbe','Visionäre Führung, Inspiration, Unternehmergeist und natürliche Autorität.','Dominanz, Ungeduld und aufgeblähtes Ego.','["vision","führung","unternehmen"]'

  UNION ALL SELECT 'ace-of-pentacles','en','Ace of Pentacles','New material opportunity, abundance, practicality and success.','Material loss, weak planning and greed.','["money","opportunity","success"]'
