  UNION ALL SELECT 'eight-of-pentacles','en','Eight of Pentacles','Mastery, care, skill-building and focused work.','Carelessness, boredom and low-quality work.','["mastery","care","learning"]'
  UNION ALL SELECT 'eight-of-pentacles','de','Acht der Münzen','Meisterschaft, Sorgfalt, Fähigkeitsaufbau und fokussierte Arbeit.','Nachlässigkeit, Langeweile und minderwertige Arbeit.','["meisterschaft","sorgfalt","lernen"]'
