  UNION ALL SELECT 'queen-of-pentacles','en','Queen of Pentacles','Abundance, nurturing, practical wisdom and home-work balance.','Neglect, imbalance, financial worry and lack of self-care.','["abundance","nurturing","balance"]'
  UNION ALL SELECT 'queen-of-pentacles','de','Königin der Münzen','Fülle, Fürsorge, praktische Weisheit und Balance zwischen Zuhause und Arbeit.','Vernachlässigung, Ungleichgewicht, finanzielle Sorge und fehlende Selbstfürsorge.','["fülle","fürsorge","balance"]'
