) v ON v.slug = c.slug
ON DUPLICATE KEY UPDATE
  name = VALUES(name),
  upright_meaning = VALUES(upright_meaning),
  reversed_meaning = VALUES(reversed_meaning),
  keywords = VALUES(keywords);
